```class Solution {
    public int peopleAwareOfSecret(int n, int delay, int forget) {
        long[] dp = new long[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            dp[i] = (dp[i - 1] + dp[Math.max(0, i - delay)] - dp[Math.max(0, i - forget)]) % 1000000007;
        }
        return (int) dp[n];
    }
}```
